import network
import time
from umqtt.simple import MQTTClient
import machine
import dht

# WiFi credentials - use secure methods to manage these
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# MQTT broker details
MQTT_BROKER = "mqtt.yourdomain.com"
MQTT_PORT = 8883
MQTT_CLIENT_ID = "esp32_sensor_" + str(machine.unique_id())
MQTT_TOPIC = "sensors/temp"

# Initialize DHT sensor
sensor = dht.DHT22(machine.Pin(4))

# WiFi connection
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        while not wlan.isconnected():
            time.sleep(1)
    print("WiFi connected:", wlan.ifconfig())

# MQTT connection with secure settings
def connect_mqtt():
    client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER, port=MQTT_PORT, ssl=True)
    # Use secure authentication if required
    # client.connect()
    return client

# Main loop
def main():
    connect_wifi()
    
    # Connect to MQTT broker
    try:
        client = connect_mqtt()
        # client.connect()  # Uncomment if authentication is needed
        print("Connected to MQTT broker")
    except Exception as e:
        print("MQTT connection failed:", e)
        return
    
    while True:
        try:
            # Read sensor data
            sensor.measure()
            temperature = sensor.temperature()
            
            # Validate sensor data
            if -40 <= temperature <= 80:
                # Publish to MQTT
                client.publish(MQTT_TOPIC, str(temperature))
                print("Published temperature:", temperature)
            else:
                print("Invalid temperature reading")
                
        except Exception as e:
            print("Error reading sensor:", e)
            
        time.sleep(60)  # Publish every minute

# Run main function
main()